---
import type { HTMLAttributes } from "astro/types"
import type { TooltipAlign, TooltipSide } from "@data-slot/tooltip"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"div"> & {
  delay?: number
  skipDelayDuration?: number
  side?: TooltipSide
  align?: TooltipAlign
  sideOffset?: number
  alignOffset?: number
  avoidCollisions?: boolean
  collisionPadding?: number
  portal?: boolean
}

const {
  class: className,
  delay = 300,
  skipDelayDuration = 300,
  side = "top",
  align = "center",
  sideOffset = 4,
  alignOffset = 0,
  avoidCollisions = true,
  collisionPadding = 8,
  portal = true,
  ...props
} = Astro.props
---

<div
  data-slot="tooltip"
  data-delay={delay}
  data-skip-delay-duration={skipDelayDuration}
  data-side={side}
  data-align={align}
  data-side-offset={sideOffset}
  data-align-offset={alignOffset}
  data-avoid-collisions={avoidCollisions}
  data-collision-padding={collisionPadding}
  data-portal={portal}
  class={cn(className)}
  {...props}
>
  <slot />
</div>

<script>
  import { create } from "@data-slot/tooltip"

  create()
</script>

---
import type { HTMLAttributes } from "astro/types"
import type { TooltipAlign, TooltipSide } from "@data-slot/tooltip"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"div"> & {
  side?: TooltipSide
  align?: TooltipAlign
  sideOffset?: number
  alignOffset?: number
  avoidCollisions?: boolean
  collisionPadding?: number
}

const {
  class: className,
  hidden = true,
  side,
  align,
  sideOffset,
  alignOffset,
  avoidCollisions,
  collisionPadding,
  ...props
} = Astro.props
---

<div data-slot="tooltip-portal">
  <div
    data-slot="tooltip-positioner"
    data-side={side}
    data-align={align}
    data-side-offset={sideOffset}
    data-align-offset={alignOffset}
    data-avoid-collisions={avoidCollisions}
    data-collision-padding={collisionPadding}
    class="z-50"
  >
    <div
      data-slot="tooltip-content"
      data-side={side}
      data-align={align}
      data-side-offset={sideOffset}
      data-align-offset={alignOffset}
      data-avoid-collisions={avoidCollisions}
      data-collision-padding={collisionPadding}
      hidden={hidden}
      class={cn(
        "bg-foreground text-background data-[side=bottom]:slide-in-from-top-2 data-[side=inline-end]:slide-in-from-left-2 data-[side=inline-start]:slide-in-from-right-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 data-[state=delayed-open]:animate-in data-[state=delayed-open]:fade-in-0 data-[state=delayed-open]:zoom-in-95 data-open:animate-in data-open:fade-in-0 data-open:zoom-in-95 data-closed:animate-out data-closed:fade-out-0 data-closed:zoom-out-95 z-50 inline-flex w-fit max-w-xs origin-(--transform-origin) items-center gap-1.5 rounded-md px-3 py-1.5 text-xs has-data-[slot=kbd]:pr-1.5 data-[instant]:animate-none data-[instant]:transition-none **:data-[slot=kbd]:relative **:data-[slot=kbd]:isolate **:data-[slot=kbd]:z-50 **:data-[slot=kbd]:rounded-sm",
        className
      )}
      {...props}
    >
      <slot />
      <div
        data-slot="tooltip-arrow"
        aria-hidden="true"
        class="bg-foreground fill-foreground z-50 size-2.5 rotate-45 rounded-[2px] data-[side=bottom]:-top-1 data-[side=inline-end]:-left-1 data-[side=inline-end]:translate-x-[1.5px] data-[side=inline-start]:-right-1 data-[side=inline-start]:-translate-x-[1.5px] data-[side=left]:-right-1 data-[side=left]:-translate-x-[1.5px] data-[side=right]:-left-1 data-[side=right]:translate-x-[1.5px] data-[side=top]:-bottom-1"
      >
      </div>
    </div>
  </div>
</div>
